retrieving revision 1.4
diff -u -r1.4 mesg.c
--- /usr/src/usr.bin/mesg/mesg.c	28 Aug 1999 01:03:59 -0000	1.4
+++ /usr/src/usr.bin/mesg/mesg.c	24 Jul 2002 14:39:28 -0000
@@ -56,7 +56,6 @@
 #include <err.h>
 #include <stdio.h>
 #include <stdlib.h>
-#include <string.h>
 #include <unistd.h>

 static void usage __P((void));
@@ -79,33 +78,32 @@
 	argc -= optind;
 	argv += optind;

-	if ((tty = ttyname(STDERR_FILENO)) == NULL)
-		err(1, "ttyname");
+	if ((tty = ttyname(STDIN_FILENO)) == NULL &&
+	    (tty = ttyname(STDOUT_FILENO)) == NULL &&
+	    (tty = ttyname(STDERR_FILENO)) == NULL)
+		err(2, "unknown tty");
+
 	if (stat(tty, &sb) < 0)
-		err(1, "%s", tty);
+		err(2, "%s", tty);

 	if (*argv == NULL) {
-		if (sb.st_mode & S_IWGRP) {
-			(void)fprintf(stderr, "is y\n");
-			exit(0);
-		}
-		(void)fprintf(stderr, "is n\n");
-		exit(1);
+		(void)printf("is %s\n", sb.st_mode & S_IWGRP ? "y" : "n");
+		return(sb.st_mode & S_IWGRP ? 0 : 1);
 	}

-	switch (*argv[0]) {
+	switch (argv[0][0]) {
 	case 'y':
 		if (chmod(tty, sb.st_mode | S_IWGRP) < 0)
-			err(1, "%s", tty);
-		exit(0);
+			err(2, "%s", tty);
+		break;
 	case 'n':
 		if (chmod(tty, sb.st_mode & ~S_IWGRP) < 0)
-			err(1, "%s", tty);
-		exit(1);
+			err(2, "%s", tty);
+		break;
+	default:
+		usage();
 	}
-
-	usage();
-	return(0);
+	return(sb.st_mode & S_IWGRP ? 0 : 1);
 }

 static void

